        A_MINSTREL_FROM_WINDURST_EH_YES_I_KNOW                                  = 6734,  -- A minstrel from Windurst, eh? Yes, I know a Jatan-Paratan, as a matter of fact. Long ago we undertook a perilous journey together.
        NOW_THAT_YOU_MENTION_IT_I_RECENTLY_HAD                                  = 6735,  -- Now that you mention it, I recently had the good fortune to visit Windurst, and ran into my old friend in a tavern there.
        AS_ALWAYS_HIS_MUSIC_TALENTS_ARE_QUITE_FORMIDABLE                        = 6736,  -- As always, his music talents are quite formidable. His performance there moved me deeply.
        BUT_TO_SAY_GOODBYE_IN_SUCH_A_PLAIN                                      = 6737,  -- But to say goodbye in such a plain setting would hardly fit such a maestro, so I bade him to visit glorious Jeuno.
