        OH_I_SEE_SO_THAT_WAS_WHAT_WAS                                           = 6743,  -- Oh, I see... So that was what was troubling Jatan-Paratan.
        OBVIOUSLY_I_WAS_NAIVE_PERHAPS_IT_WOULD_BEHOOVE                          = 6744,  -- Obviously I was naive. Perhaps it would behoove me to rethink the true meaning of music. A thousand thanks, traveler!
