        AND_THEY_RE_A_GREAT_WAY_TO_BREAK                                        = 7758,  -- And they're a great way to break the ice with strangers, don't you think?
        I_HEARD_JEUNO_BEGAN_ABOUT_EIGHTY_YEARS_AGO                              = 7759,  -- I heard Jeuno began about eighty years ago when fishermen settled here. It was just a tiny fishing village back then.
        AS_YOU_CAN_SEE_FROM_ANY_MAP_JEUNO                                       = 7760,  -- As you can see from any map, Jeuno lies on a crossroads binding the three nations together. A hub of commerce, Jeuno grew wealthy.
        SOON_IT_WAS_FILLED_WITH_THE_BUSTLE_OF                                   = 7761,  -- Soon it was filled with the bustle of buyer and seller. Our humble district captures that particular energy better than any other.
        HUH_WHAT_AM_I_DOING_HERE_I_M                                            = 7762,  -- Huh? What am I doing here? I'm looking for work! I got fired from my last place. Something about talking too much...
