        OF_ITEM_IS_IT_VERY_WELL_YOUR_PRECIOUS                                   = 10212,  -- # [variety/varieties] of item, is it? Very well! Your precious property is safe with me, kupo!
        IS_THAT_A_MAGIAN_INSIGNIA_I_SEE_ON                                      = 10213,  -- Is that a Magian insignia I see on that %? You'll have to abandon your trial before I can take it off your hands, kupo.
