        WAIT_BUT_A_MOMENT_HERE_FOLLOW_THIS_COMMAND                              = 10591,  -- Wait but a moment. Here, follow this command--er, compendium to the letter and you should be able to learn a thing or two.
        AH_THIS_ALMOST_SLIPPED_MY_MIND_SHOULD_YOU                               = 10592,  -- Ah, this almost slipped my mind. Should you receive any distinct sorts of artifacts for completing an objective, I will be happy to take them off your hands.
        WORRY_NOT_FOR_I_AM_NOT_OUT_TO                                           = 10593,  -- Worry not, for I am not out to rob you of your glory. Quite the opposite, in fact. I will provide you with a worthwhile reward for collecting them.
        THANKS_TO_YOUR_DONATION_I_NOW_HAVE_IN                                   = 10594,  -- Thanks to your donation, I now have # in safekeeping.
