        WANNA_GO_AGAIN                                                          = 10933,  -- Wanna go again?
        KEEP_GOIN_LEMME_AT_IT_THANKS_BUT_NO                                     = 10934,  -- Keep goin'? Lemme at it! Thanks, but no thanks.
        YER_DAILY_TALLY_IT_S_UM_Y_KNOW                                          = 10935,  -- Yer daily tally? It's, um... Y'know, 'round # [point/points] or thereamabouts.
        LEMME_CHECK_FOR_YA_WELL_IT_COULDA_BEEN                                  = 10936,  -- Lemme check for ya! Well, it coulda been %, %, or mebbe even %. What? Ya thinks ya could do better wit' one o' dese Gobbie masks on!?
        ANYWISE_WHERE_D_DA_MYST_RY_BE_IF                                        = 10937,  -- Anywise, where'd da myst'ry be if ya's knew da answer 'fore ya opens it?
        SOME_THINGS_IS_BETTER_LEFT_UNKNOWN_GOTTA_LEAVE                          = 10938,  -- Some things is better left unknown. Gotta leave a little room fer romanchismo in da woild, y'know.
        DERE_WE_GOES_DA_MYST_RY_BOX_SEEMS                                       = 10939,  -- Dere we goes. Da myst'ry box seems tah like yer offerin'...but it wants more. Got anythin' else ya wanna throw away?
        DERE_WE_GOES_OHO_LOOKS_LIKE_IT_DON                                      = 10940,  -- Dere we goes. Oho, looks like it don't wants no more. Guess ya gotta come back tomorrow if ya's wanna keep gettin' rid o' stuff.
