        WHAT_LL_IT_BE_BEGINNER_LIST_INTERMEDIATE_LIST_2                         = 10957,  -- What'll it be? Beginner list. Intermediate list. Advanced list. Where's Tenzen? Pay the # gil. Please explain again. Let me think about it.
        AH_YES_TENZEN_MENTIONED_THAT_YOU_MIGHT_BE                               = 10958,  -- Ah yes, Tenzen mentioned that you might be passing through.
        THE_AMBASSADOR_SET_HIS_SIGHTS_ON_AHT_URHGAN                             = 10959,  -- The ambassador set his sights on Aht Urhgan, no?
        GIVEN_THAT_YOU_RE_TRYING_TO_SAVE_THE                                    = 10960,  -- Given that you're trying to save the world...I'll let you board for free. Rather magnanimous, wouldn't you say?
