        URK_2                                                                   = 10963,  -- Urk!
        Y_KNOW_WHAT_THEY_SAY_YOU_CAN_PICK                                       = 10964,  -- Y'know what they say. You can pick your friends and you can pick your nose, but you can't...heh heh heh.
        SO_GIVE_HIM_HER_AND_BE_DONE_WITH                                        = 10965,  -- So give him/her] % and be done with it.
        HEY_DID_CHACHAROON_SEND_YA_HERE_FO_THE                                  = 10966,  -- Hey, did Chacharoon send ya? Here fo' the usual?
        OOOYA_STINKNIX_GOBBIE_FIX_SUSUROON_S_BEST_SPRINKLE                      = 10967,  -- Oooya, Stinknix! Gobbie fix Susuroon's best sprinkle box yet?
        HOW_YA_DOIN_SU_I_GOT_YO_WATERIN                                         = 10968,  -- How ya doin', Su'. I got yo' waterin' can right here, good as new!
