        WHA_WHA_WHAT_HE_TRY_RAISE_FOUR_BEASTIES                                 = 10972,  -- Wha--wha--what!? He try raise four beasties? No good. Chacharoon become mini monster meal! Drop into full-dead this time if no careful.
        BUT_IF_ALL_WORK_TOGETHER_LIKE_HOUSE_TRIBE                               = 10973,  -- But, if all work together like house-tribe, maybe not so hard. If house-tribe look out for one another, Chacharoon no give eye water for sure.
        I_DON_T_KNOW_HOW_YOU_KEEP_TRACK                                         = 10974,  -- I don't know how you keep track of all 'em kids ya got, Su'.
